import { router, publicProcedure } from '../trpc';
import { z } from 'zod';

export const mockPosts = Array.from({ length: 15 }).map((_, i) => ({
  id: i,
  title: `Post ${i}`,
}));

export const postsRouter = router({
  list: publicProcedure
    .input(
      z.object({
        limit: z.number().min(1).max(50),
        cursor: z.number().optional(),
      }),
    )
    .query(({ input }) => {
      const startIndex = input.cursor ?? 0;
      const endIndex = startIndex + input.limit;
      const items = mockPosts.slice(startIndex, endIndex);
      const nextCursor = endIndex < mockPosts.length ? endIndex : null;

      return {
        items,
        nextCursor,
      };
    }),
});

'use client';

import { trpc } from '../../trpc/client';
import React from 'react';

export function PostList() {
  const [data, { fetchNextPage, hasNextPage, isFetchingNextPage }] =
    trpc.posts.list.useSuspenseInfiniteQuery(
      { limit: 5 },
      {
        getNextPageParam: (lastPage) => lastPage.nextCursor,
      },
    );

  const posts = data.pages.flatMap((page) => page.items);

  return (
    <div>
      <h2>Posts</h2>
      <ul>
        {posts.map((post) => (
          <li key={post.id}>{post.title}</li>
        ))}
      </ul>
      <button
        type="button"
        onClick={() => fetchNextPage()}
        disabled={!hasNextPage || isFetchingNextPage}
      >
        Load More
      </button>
    </div>
  );
}

